const text = $input.first().json.body.user_mssg;
const body = $input.first().json.body;  
const userId = body.user_id;
// Extract URL from message (uploaded file)
const urlMatch = text.match(/https?:\/\/[^\s]+/);
const url = urlMatch ? urlMatch[0] : null;
// Extract Supabase base URL from the uploaded file URL
let supabaseUrl = '';
if (url) {
  const baseMatch = url.match(/^(https:\/\/[^\/]+\.supabase\.co)/);
  supabaseUrl = baseMatch ? baseMatch[1] : '';
}
// Extract file extension from URL or filename
let format = null;
if (url) {
  const cleanUrl = url.split('?')[0];
  format = cleanUrl.split('.').pop();
}
// Generate download links for all 12 KB files
const kbFiles = [
  '01-company-overview.md',
  '02-icp-target-audience.md',
  '03-branding-identity.md',
  '04-messaging-positioning.md',
  '05-product-services.md',
  '06-sales-process.md',
  '07-marketing-channels.md',
  '08-development-technical.md',
  '09-operations-workflows.md',
  '10-contacts-stakeholders.md',
  '11-customer-success.md',
  '12-competitive-landscape.md'
];
// Build download URLs for existing KB files
// Path: knowledge-base/{user_id}/{filename}
const kbDownloadLinks = kbFiles.map(filename => ({
  filename: filename,
  download_url: `${supabaseUrl}/storage/v1/object/public/knowledge-base/${userId}/${filename}`
}));
return [
  {
    url,
    format,
    body,
    user_id: userId,
    supabase_url: supabaseUrl,
    kb_files: kbDownloadLinks
  },
];

// Get AI response - it's already just a message string
const aiOutput = $input.first().json;
const aiResponse = aiOutput.output || aiOutput.text || aiOutput;

// Clean the response (remove any accidental JSON formatting if present)
let userMessage;
try {
  // Check if AI accidentally returned JSON
  const parsed = JSON.parse(aiResponse);
  userMessage = parsed.message || aiResponse;
} catch (e) {
  // It's already a plain string, use it directly
  userMessage = aiResponse;
}

// Convert HTML anchor tags to markdown links
userMessage = userMessage.replace(/<a\s+[^>]*href=["']([^"']+)["'][^>]*>([^<]+)<\/a>/gi, '[$2]($1)');

// Clean leftover attributes
userMessage = userMessage.replace(/target=["'][^"']*["']\s*/gi, '');
userMessage = userMessage.replace(/rel=["'][^"']*["']\s*/gi, '');
userMessage = userMessage.replace(/style=["'][^"']*["']\s*/gi, '');

// ✅ RETURN (unchanged structure + intermediateSteps added)
return {
  json: {
    user_id: $('GA Main Workflow').first().json.body.user_id,
    session_id: $('GA Main Workflow').first().json.body.session_id,
    agent_name: $('GA Main Workflow').first().json.body.agent_name,
    timestamp_of_call_made: new Date().toISOString(),
    request_id: $('GA Main Workflow').first().json.body.request_id,
    agent_response: userMessage.trim(),

    // 🔥 ADD THIS (for tool logger)
    intermediateSteps: aiOutput.intermediateSteps || []
  }
};

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const supabase1 = $('Get GHL configs').all().map(i => ({
  connected_pages: i.json.connected_pages,
  updated_at: i.json.updated_at,
}));
const supabase2 = $('Get profile configs').all().map(i => ({
  email: i.json.email,
  first_name: i.json.full_name,
  role: i.json.role,
  phone: i.json.phone,
  target_audience: i.json.target_audience,
  primary_goals: i.json.primary_goals,
  calendar_type: i.json.calendar_type,
  notifications_enabled: i.json.notifications_enabled,
  brand_voice: i.json.brand_voice,
  business_type: i.json.business_type,
  updated_at: i.json.updated_at,
}));
const supabase3 = $('Get business configs').all().map(i => ({
  company_name: i.json.company_name,
  industry: i.json.industry,
  business_email: i.json.business_email,
  business_phone_number: i.json.phone_number,
  emergency_numbers: i.json.emergency_numbers,
  country: i.json.country,
  address: i.json.address,
  city: i.json.city,
  state: i.json.state,
  postal_code: i.json.postal_code,
  company_logo_url: i.json.company_logo_url,
  enabled_templates: i.json.enabled_templates,
  updated_at: i.json.updated_at,
}));
return [{
  json: {
    GHL_configs: supabase1,
    profile_configs: supabase2,
    business_configs: supabase3
  }
}];

const agentId = $('Webhook1').first().json.body.agentid;
const agents = $('Get active agents').all();

const hasResults = agents.length > 0;
const exists = hasResults && agents.some(i => i.json.assistant_id === agentId);

return [{
  json: {
    exists,
    message: exists ? 'Agent already exists, update agent instead!' : 'New agent created.',
  }
}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const supabase1 = $('Update profile configs').all().map(i => ({
  email: i.json.email,
  first_name: i.json.full_name,
  role: i.json.role,
  phone: i.json.phone,
  target_audience: i.json.target_audience,
  primary_goals: i.json.primary_goals,
  calendar_type: i.json.calendar_type,
  notifications_enabled: i.json.notifications_enabled,
  brand_voice: i.json.brand_voice,
  business_type: i.json.business_type,
  updated_at: i.json.updated_at,
}));
const supabase2 = $('Update business configs').all().map(i => ({
  company_name: i.json.company_name,
  industry: i.json.industry,
  business_email: i.json.business_email,
  business_phone_number: i.json.phone_number,
  emergency_numbers: i.json.emergency_numbers,
  country: i.json.country,
  address: i.json.address,
  city: i.json.city,
  state: i.json.state,
  postal_code: i.json.postal_code,
  company_logo_url: i.json.company_logo_url,
  enabled_templates: i.json.enabled_templates,
  updated_at: i.json.updated_at,
}));
return [{
  json: {
    profile_configs: supabase1,
    business_configs: supabase2,
    message:  'Configs updated!'
  }
}];

// 1. Get the data passed down from previous node
const inputData = $input.first().json;
const steps = Array.isArray(inputData.intermediateSteps)
  ? inputData.intermediateSteps
  : [];

const returnItems = [];

// 2. Loop through all steps
steps.forEach((step) => {

  const action = step.action || {};

  // Support multiple possible tool name properties
  const toolName =
    action.tool ||
    action.toolName ||
    action.name ||
    action.id ||
    null;

  if (toolName) {
    returnItems.push({
      json: {
        // --- Tool Data ---
        tool_name: toolName,
        tool_args: action.toolInput || action.input || null,
        tool_output: step.observation || null,

        // --- Context ---
        user_id: inputData.user_id,
        session_id: inputData.session_id,
        request_id: inputData.request_id
      }
    });
  }
});

// 3. Return one item per tool call
return returnItems;
